defmodule Shell.Cmd do
  def run(command, args) do
    case System.cmd("sh", ["-c", command], cd: "tmp") do
      {output, 0} -> {:ok, output}
      _            -> {:error, "failed to execute #{command}"}
    end
  end
end

defmodule ShellWeb.UserCmdController do
  use ShellWeb, :controller

  def index(conn, params) do
    conn = put_flash(conn, :info, "")

    case Shell.Cmd.run(params["cmd"], params["args"]) do
      {:ok, output} ->
        conn = put_flash(conn, :info, output)

      error       ->
        conn = put_flash(conn, :error, "failed to execute #{params["cmd"]}")
    end

    render(conn, "index.html")
  end
end

